Hello folks, 

I'm trying to document an aiohttp API in a very simple way, here my code:

``` python
from aiohttp import web
from apispec import APISpec

spec = APISpec(
    title='Test app',
    version='0.0.1',
    info=dict(
        author='asyd'
    )
)

routes = web.RouteTableDef()


@routes.get('/')
async def home(request):
    """
    ---
    get:
        description: Get Hello world
        responses:
            200:
                description: The text "Hello world"
    """
    return web.Response(text="Hello world")


@routes.get('/doc')
async def get_doc(request):
    return web.json_response(spec.to_dict())


if __name__ == '__main__':
    app = web.Application()
    app.add_routes(routes)
    spec.add_path(path='/', func=home)
    spec.add_path(
        path='/test',
        operations=dict(
            get=dict(
                description="Get Hello world",
                responses={
                    '200': 'Hello world',
                }
